oxy_webhelp_navlinks = {"postgresql_recovery-d30753e33825":{"topics":[{"title":"PostgreSQL recovery options","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides flexible options for PostgreSQL cluster recovery from         secure, immutable backups.<\/p>","href":"postgresql\/postgresql_recovery_options.html","attributes":{"data-id":"postgresql_recovery_options"},"menu":{"hasChildren":false},"tocID":"postgresql_recovery_options-d30753e33839","topics":[]},{"title":"Creating a restore mount point for a PostgreSQL cluster","shortdesc":"<p class=\"shortdesc\">To recover a PostgreSQL cluster, create a restore mount point by mounting a snapshot         of backup data to the mount point using NFS and then performing the recovery         instructions.<\/p>","href":"postgresql\/creating_restore_mp_postgresql.html","attributes":{"data-id":"creating_restore_mp_postgresql"},"menu":{"hasChildren":false},"tocID":"creating_restore_mp_postgresql-d30753e33852","topics":[]},{"title":"Unmounting restore mount point after PostgreSQL cluster recovery","shortdesc":"<p class=\"shortdesc\">After recovering a PostgreSQL cluster, unmount it to remove the metadata associated         with the selected PostgreSQL cluster.<\/p>","href":"postgresql\/unmounting_restore_mount_point_postgresql_cluster.html","attributes":{"data-id":"unmounting_restore_mount_point_postgresql_cluster"},"menu":{"hasChildren":false},"tocID":"unmounting_restore_mount_point_postgresql_cluster-d30753e33863","topics":[]},{"title":"Recovering a PostgreSQL cluster","shortdesc":"<p class=\"shortdesc\">After you have created a mount point for the PostgreSQL cluster, recover the cluster         manually by following the recovery instructions.<\/p>","href":"postgresql\/recovering_postgresql_cluster.html","attributes":{"data-id":"recovering_postgresql_cluster"},"menu":{"hasChildren":false},"tocID":"recovering_postgresql_cluster-d30753e33874","topics":[]},{"title":"PostgreSQL automated recovery","shortdesc":"<p class=\"shortdesc\">PostgreSQL automated recovery enables you to recover PostgreSQL clusters on <span class=\"ph\">RSC<\/span> from Rubrik CDM versions 9.4.1 and later without requiring manual         steps.<\/p>","href":"postgresql\/postgresql_automated_recovery.html","attributes":{"data-id":"postgresql_automated_recovery"},"menu":{"hasChildren":false},"tocID":"postgresql_automated_recovery-d30753e33885","next":"postgresql_automated_recovery-d30753e33885"}]}};